// STRIPS Operator Schema
OPERATOR = {
 name: "stack(block, onto_block)",
 parameters: [?x, ?y],

 // Preconditions: What must be true before action
 preconditions: [
 holding(?x),
 clear(?y)
 ],

 // Effects: What changes after action
 add_list: [
 handempty,
 on(?x, ?y),
 clear(?x)
 ],

 delete_list: [
 holding(?x),
 clear(?y)
 ]
}

FUNCTION Forward-Planning-Search(problem):
 frontier = [Initial-Node(problem.initial)]

 while frontier is not empty:
 node = Select-Node(frontier)

 if Problem-Goal-Test(problem, node.state):
 return Solution(node)

 // Expand: generate successors by applying all applicable actions
 for each action in problem.operators:
 ifapplicable(action, node.state):
 next_state = Apply(action, node.state)
 child = Node(state: next_state, parent: node, action: action)
 frontier.add(child)

 return failure

FUNCTION Backward-Planning-Search(problem):
 goals = problem.goal
 frontier = [goals]

 while frontier is not empty:
 goalset = Select-Goal-Set(frontier)

 if goalset is subset of problem.initial:
 return Reconstruct-Plan(goalset)

 // Find actions that can achieve some goal
 for each action in relevant_actions(goalset):
 regressed = Regression(action, goalset)
 // Only consider if consistent (no contradictions)
 if consistent(regressed):
 frontier.add(regressed)

 return failure

FUNCTION Regression(action, goals):
 // Compute what must be true before action
 new_goals = goals - action.effects.add
 new_goals = new_goals ∪ action.preconditions
 return new_goals

FUNCTION GraphPlan(problem):
 // Phase 1: Build planning graph
 graph = Initialize-Graph(problem.initial)

 while not All-Goals-Level(graph, problem.goals):
 graph = Expand-Graph(graph)
 if graph has reached fixed point:
 return failure

 // Phase 2: Extract solution
 return Extract-Solution(graph, problem.goals)

FUNCTION Expand-Graph(graph):
 // Add action level
 actions = Get-All-Actions(graph.current_propositions)
 graph.add_action_level(actions)

 // Add mutex links between conflicting actions
 graph.add_mutex_links()

 // Add proposition level (effects of actions)
 propositions = Get-Effects(actions)
 graph.add_proposition_level(propositions)

 // Add mutex links between propositions
 graph.add_mutex_links()

 return graph

FUNCTION Extract-Solution(graph, goals):
 // Backward search from goal level
 level = graph.goal_level
 while level > 0:
 // Select subset of actions achieving goals
 actionset = Select-Actions(graph, goals, level)
 if actionset is empty:
 return failure (backtrack needed)
 goals = Regression-Through(actionset, goals)
 level = level - 1

 return Build-Plan(actionset)

FUNCTION Partial-Order-Plan(initial, goals):
 // Initialize plan with Start and Finish actions
 plan = {
 steps: {S0: Action(initial), Sg: Action(goals)},
 orderings: [(S0, Sg)],
 bindings: {},
 constraints: []
 }

 // Add initial goals as open preconditions
 open_preconditions = Get-Preconditions(Sg) - Get-Effects(S0)

 while open_preconditions is not empty:
 // Select an open precondition
 prec = Select(open_preconditions)
 open_preconditions.remove(prec)

 // Find or create an action to achieve it
 candidate = Find-Action-For(prec, plan)
 if no candidate exists:
 return failure (backtrack)

 // Add causal link: candidate achieves prec
 plan.steps.add(candidate)
 plan.constraints.add(Causal-Link(candidate, prec))
 plan.orderings.add((candidate, Sg))

 // Check for threats and resolve
 threats = Find-Threats(plan, candidate)
 for each threat in threats:
 if not Resolve-Threat(plan, threat):
 return failure (backtrack)

 // Update open preconditions
 new_precs = Get-Preconditions(candidate) - Get-Effects(S0)
 open_preconditions.add(new_precs)

 return plan

FUNCTION Resolve-Threat(plan, threat):
 // Threat: action T threatens causal link A → B
 // Resolution: promote T before A, or demote T after B
 // Try both, backtrack if neither works
 if Try-Promote(plan, threat): return true
 if Try-Demote(plan, threat): return true
 return false
